        subjectCases[_subject].push(id);

        investigators[msg.sender].investigationsCount++;

        emit InvestigationCreated(id, msg.sender, _subject, _subjectType, _riskScore);

        return id;
    }

    function verifyInvestigation(uint256 _id) external onlyOwner {
        Investigation storage inv = investigations[_id];
        require(inv.id != 0, "Investigation not found");
        require(!inv.verified, "Already verified");

        inv.verified = true;

        // Calculate reward based on risk score and accuracy
        uint256 baseReward = 0.001 ether;
        uint256 riskMultiplier = inv.riskScore >= 80 ? 3 : inv.riskScore >= 50 ? 2 : 1;
        uint256 reputationBonus = investigators[inv.investigator].reputation / 100;

        inv.rewardAmount = baseReward * riskMultiplier + reputationBonus;
        pendingRewards[inv.investigator] += inv.rewardAmount;

        investigators[inv.investigator].successfulInvestigations++;
        _updateReputation(inv.investigator, 10);

        emit InvestigationVerified(_id, msg.sender);
    }

    function voteOnInvestigation(uint256 _id, bool _isUpvote) external onlyRegistered {
        Investigation storage inv = investigations[_id];
        require(inv.id != 0, "Investigation not found");
        require(inv.investigator != msg.sender, "Can't vote on own investigation");

        if (_isUpvote) {
            require(!inv.upvotes[msg.sender], "Already upvoted");
            inv.upvotes[msg.sender] = true;
            inv.upvoteCount++;

            if (inv.downvotes[msg.sender]) {
                inv.downvotes[msg.sender] = false;
                inv.downvoteCount--;
            }
        } else {
            require(!inv.downvotes[msg.sender], "Already downvoted");
            inv.downvotes[msg.sender] = true;
            inv.downvoteCount++;

            if (inv.upvotes[msg.sender]) {
                inv.upvotes[msg.sender] = false;
                inv.upvoteCount--;
            }
        }

        emit VoteCast(_id, msg.sender, _isUpvote);
    }

    // ═══════════════════════════════════════════════════════════
    // INVESTIGATOR PROFILE FUNCTIONS
    // ═══════════════════════════════════════════════════════════

    function registerInvestigator(string memory _handle) external whenNotPaused {
        require(investigators[msg.sender].wallet == address(0), "Already registered");
        require(bytes(_handle).length >= 3, "Handle too short");

        InvestigatorProfile storage profile = investigators[msg.sender];
        profile.wallet = msg.sender;
        profile.handle = _handle;
        profile.reputation = 100; // Starting reputation
        profile.joinDate = block.timestamp;

        registeredInvestigators.push(msg.sender);

        emit InvestigatorRegistered(msg.sender, _handle);
    }

    function _updateReputation(address _investigator, int256 _delta) internal {
        InvestigatorProfile storage profile = investigators[_investigator];

        if (_delta > 0) {
            profile.reputation += uint256(_delta);
        } else {
            uint256 decrease = uint256(-_delta);
            profile.reputation = profile.reputation > decrease ? profile.reputation - decrease : 0;
        }

        emit ReputationUpdated(_investigator, profile.reputation);
    }

    // ═══════════════════════════════════════════════════════════
    // TOKEN ALERT FUNCTIONS
    // ═══════════════════════════════════════════════════════════

    function createTokenAlert(
        address _token,
        uint8 _riskLevel,
        string memory _reason,
        string memory _evidenceHash
    ) external onlyOwner {
        require(_riskLevel >= 1 && _riskLevel <= 4, "Invalid risk level");

        TokenAlert storage alert = tokenAlerts[_token];
        alert.tokenAddress = _token;
        alert.riskLevel = _riskLevel;
        alert.reason = _reason;
        alert.evidenceHash = _evidenceHash;
        alert.timestamp = block.timestamp;
        alert.active = true;

        alertedTokens.push(_token);

        emit TokenAlertCreated(_token, _riskLevel, _reason);
    }

    function updateTokenAlert(address _token, bool _active) external onlyOwner {
        require(tokenAlerts[_token].tokenAddress != address(0), "Alert not found");

        tokenAlerts[_token].active = _active;

        emit TokenAlertUpdated(_token, _active);
    }

    // ═══════════════════════════════════════════════════════════
    // REWARD FUNCTIONS
    // ═══════════════════════════════════════════════════════════

    function claimReward() external onlyRegistered {
        uint256 amount = pendingRewards[msg.sender];
        require(amount > 0, "No rewards pending");

        pendingRewards[msg.sender] = 0;
        totalRewardsDistributed += amount;

        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Transfer failed");

        emit RewardClaimed(msg.sender, amount);
    }

    function fundRewards() external payable onlyOwner {
        // Accept ETH to fund reward pool
    }

    // ═══════════════════════════════════════════════════════════
    // ADMIN FUNCTIONS
    // ═══════════════════════════════════════════════════════════

    function setPlatformFee(uint256 _newFee) external onlyOwner {
        require(_newFee <= 20, "Fee too high");
        platformFeePercent = _newFee;
    }

    function setScoringWeight(string memory _factor, uint256 _weight) external onlyOwner {
        scoringWeights[_factor] = _weight;
    }

    function pause() external onlyOwner {
        paused = true;
    }

    function unpause() external onlyOwner {
        paused = false;
    }

    function transferOwnership(address _newOwner) external onlyOwner {
        pendingOwner = _newOwner;
    }

    function acceptOwnership() external {
        require(msg.sender == pendingOwner, "Not pending owner");
        owner = pendingOwner;
        pendingOwner = address(0);
    }

    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "No funds");

        (bool success, ) = payable(owner).call{value: balance}("");
        require(success, "Withdraw failed");
    }

    // ═══════════════════════════════════════════════════════════
    // VIEW FUNCTIONS
    // ═══════════════════════════════════════════════════════════

    function getInvestigation(uint256 _id) external view returns (
        address investigator,
        address subject,
        string memory subjectType,
        uint8 riskScore,
        string memory evidenceHash,
        uint256 timestamp,
        bool verified,
        uint256 rewardAmount
    ) {
        Investigation storage inv = investigations[_id];
        return (
            inv.investigator,
            inv.subject,
            inv.subjectType,
            inv.riskScore,
            inv.evidenceHash,
            inv.timestamp,
            inv.verified,
            inv.rewardAmount
        );
    }

    function getInvestigatorReputation(address _wallet) external view returns (uint256) {
        return investigators[_wallet].reputation;
    }

    function getTokenAlert(address _token) external view returns (TokenAlert memory) {
        return tokenAlerts[_token];
    }

    function getPendingReward(address _investigator) external view returns (uint256) {
        return pendingRewards[_investigator];
    }

    receive() external payable {}
}
