// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title RugMuncher CRM 2.0
 * @dev Customer Relationship Management contract for crypto investigations
 * Supports: Case management, evidence tracking, payment handling
 */
contract RugMuncherCRM is 
    Initializable, 
    AccessControlUpgradeable, 
    PausableUpgradeable,
    UUPSUpgradeable 
{
    // ═══════════════════════════════════════════════════════════
    // ROLES
    // ═══════════════════════════════════════════════════════════
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant INVESTIGATOR_ROLE = keccak256("INVESTIGATOR_ROLE");
    bytes32 public constant UPGRADER_ROLE = keccak256("UPGRADER_ROLE");

    // ═══════════════════════════════════════════════════════════
    // CONFIGURATION (Set at initialization)
    // ═══════════════════════════════════════════════════════════
    address public admin;
    address public feeRecipient;
    uint256 public platformFeeBps;  // 100 = 1%
    bool public emergencyWithdrawalEnabled;
    bool public upgradeable;

    // ═══════════════════════════════════════════════════════════
    // CASE MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    struct Case {
        uint256 id;
        address client;
        string title;
        string description;
        uint256 createdAt;
        uint256 updatedAt;
        CaseStatus status;
        uint256 budget;
        uint256 spent;
        address assignedInvestigator;
        string[] evidenceHashes;
        mapping(string => Evidence) evidence;
    }

    enum CaseStatus {
        OPEN,
        IN_PROGRESS,
        UNDER_REVIEW,
        RESOLVED,
        CLOSED,
        DISPUTED
    }

    mapping(uint256 => Case) public cases;
    mapping(address => uint256[]) public clientCases;
    mapping(address => uint256[]) public investigatorCases;
    uint256 public caseCounter;

    // ═══════════════════════════════════════════════════════════
    // EVIDENCE MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    struct Evidence {
        string ipfsHash;
        string evidenceType;  // 'transaction', 'document', 'screenshot', 'analysis'
        address submittedBy;
        uint256 submittedAt;
        string metadata;  // JSON string with additional data
        bool verified;
    }

    // ═══════════════════════════════════════════════════════════
    // PAYMENT MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    struct Payment {
        uint256 caseId;
        address from;
        address to;
        uint256 amount;
        string token;  // 'ETH', 'USDC', etc.
        uint256 timestamp;
        PaymentType pType;
        bool released;
    }

    enum PaymentType {
        CLIENT_DEPOSIT,
        MILESTONE_PAYMENT,
        REFUND,
        PLATFORM_FEE,
        INVESTIGATOR_PAYOUT
    }

    mapping(uint256 => Payment[]) public casePayments;
    mapping(address => uint256) public pendingWithdrawals;

    // ═══════════════════════════════════════════════════════════
    // EVENTS
    // ═══════════════════════════════════════════════════════════
    event CaseCreated(uint256 indexed caseId, address indexed client, string title);
    event CaseUpdated(uint256 indexed caseId, CaseStatus status, address updatedBy);
    event EvidenceAdded(uint256 indexed caseId, string ipfsHash, string evidenceType);
    event PaymentReceived(uint256 indexed caseId, address indexed from, uint256 amount, string token);
    event PaymentReleased(uint256 indexed caseId, address indexed to, uint256 amount);
    event InvestigatorAssigned(uint256 indexed caseId, address indexed investigator);

    // ═══════════════════════════════════════════════════════════
    // MODIFIERS
    // ═══════════════════════════════════════════════════════════
    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Not admin");
        _;
    }

    modifier onlyOperator() {
        require(hasRole(OPERATOR_ROLE, msg.sender) || hasRole(ADMIN_ROLE, msg.sender), "Not operator");
        _;
    }

    modifier caseExists(uint256 _caseId) {
        require(cases[_caseId].id != 0, "Case does not exist");
        _;
    }

    // ═══════════════════════════════════════════════════════════
    // INITIALIZATION
    // ═══════════════════════════════════════════════════════════
    function initialize(
        address _admin,
        address _feeRecipient,
        uint256 _platformFeeBps,
        bool _emergencyWithdrawalEnabled,
        bool _upgradeable
    ) public initializer {
        __AccessControl_init();
        __Pausable_init();
        __UUPSUpgradeable_init();

        admin = _admin;
        feeRecipient = _feeRecipient;
        platformFeeBps = _platformFeeBps;
        emergencyWithdrawalEnabled = _emergencyWithdrawalEnabled;
        upgradeable = _upgradeable;

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(ADMIN_ROLE, _admin);
        _grantRole(UPGRADER_ROLE, _admin);

        caseCounter = 0;
    }

    // ═══════════════════════════════════════════════════════════
    // CASE MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    function createCase(
        string memory _title,
        string memory _description,
        uint256 _budget
    ) external payable whenNotPaused returns (uint256) {
        caseCounter++;
        uint256 caseId = caseCounter;

        Case storage newCase = cases[caseId];
        newCase.id = caseId;
        newCase.client = msg.sender;
        newCase.title = _title;
        newCase.description = _description;
        newCase.createdAt = block.timestamp;
        newCase.updatedAt = block.timestamp;
        newCase.status = CaseStatus.OPEN;
        newCase.budget = _budget;

        clientCases[msg.sender].push(caseId);

        // Handle initial deposit
        if (msg.value > 0) {
            _processPayment(caseId, msg.sender, msg.value, "ETH", PaymentType.CLIENT_DEPOSIT);
        }

        emit CaseCreated(caseId, msg.sender, _title);
        return caseId;
    }

    function updateCaseStatus(
        uint256 _caseId, 
        CaseStatus _status
    ) external onlyOperator caseExists(_caseId) {
        cases[_caseId].status = _status;
        cases[_caseId].updatedAt = block.timestamp;
        emit CaseUpdated(_caseId, _status, msg.sender);
    }

    function assignInvestigator(
        uint256 _caseId, 
        address _investigator
    ) external onlyAdmin caseExists(_caseId) {
        require(hasRole(INVESTIGATOR_ROLE, _investigator), "Not an investigator");

        cases[_caseId].assignedInvestigator = _investigator;
        investigatorCases[_investigator].push(_caseId);

        emit InvestigatorAssigned(_caseId, _investigator);
    }

    // ═══════════════════════════════════════════════════════════
    // EVIDENCE MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    function addEvidence(
        uint256 _caseId,
        string memory _ipfsHash,
        string memory _evidenceType,
        string memory _metadata
    ) external caseExists(_caseId) {
        Case storage c = cases[_caseId];
        require(
            c.client == msg.sender || 
            c.assignedInvestigator == msg.sender || 
            hasRole(OPERATOR_ROLE, msg.sender),
            "Not authorized"
        );

        c.evidenceHashes.push(_ipfsHash);
        c.evidence[_ipfsHash] = Evidence({
            ipfsHash: _ipfsHash,
            evidenceType: _evidenceType,
            submittedBy: msg.sender,
            submittedAt: block.timestamp,
            metadata: _metadata,
            verified: false
        });

        c.updatedAt = block.timestamp;
        emit EvidenceAdded(_caseId, _ipfsHash, _evidenceType);
    }

    function verifyEvidence(
        uint256 _caseId,
        string memory _ipfsHash
    ) external onlyOperator caseExists(_caseId) {
        cases[_caseId].evidence[_ipfsHash].verified = true;
    }

    // ═══════════════════════════════════════════════════════════
    // PAYMENT MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    function depositToCase(uint256 _caseId) external payable caseExists(_caseId) whenNotPaused {
        require(msg.value > 0, "Must send ETH");
        _processPayment(_caseId, msg.sender, msg.value, "ETH", PaymentType.CLIENT_DEPOSIT);
    }

    function depositToken(
        uint256 _caseId,
        address _token,
        uint256 _amount
    ) external caseExists(_caseId) whenNotPaused {
        IERC20 token = IERC20(_token);
        require(token.transferFrom(msg.sender, address(this), _amount), "Transfer failed");
        _processPayment(_caseId, msg.sender, _amount, "ERC20", PaymentType.CLIENT_DEPOSIT);
    }

    function _processPayment(
        uint256 _caseId,
        address _from,
        uint256 _amount,
        string memory _token,
        PaymentType _pType
    ) internal {
        cases[_caseId].spent += _amount;
        casePayments[_caseId].push(Payment({
            caseId: _caseId,
            from: _from,
            to: address(this),
            amount: _amount,
            token: _token,
            timestamp: block.timestamp,
            pType: _pType,
            released: false
        }));

        emit PaymentReceived(_caseId, _from, _amount, _token);
    }

    function releasePayment(
        uint256 _caseId,
        address _to,
        uint256 _amount
    ) external onlyAdmin caseExists(_caseId) {
        // Calculate fee
        uint256 fee = (_amount * platformFeeBps) / 10000;
        uint256 payout = _amount - fee;

        // Send payout
        pendingWithdrawals[_to] += payout;
        pendingWithdrawals[feeRecipient] += fee;

        emit PaymentReleased(_caseId, _to, payout);
    }

    function withdraw() external {
        uint256 amount = pendingWithdrawals[msg.sender];
        require(amount > 0, "No pending withdrawal");
        pendingWithdrawals[msg.sender] = 0;

        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Transfer failed");
    }

    // ═══════════════════════════════════════════════════════════
    // EMERGENCY FUNCTIONS
    // ═══════════════════════════════════════════════════════════
    function emergencyWithdraw() external onlyAdmin {
        require(emergencyWithdrawalEnabled, "Emergency withdrawal not enabled");
        (bool success, ) = payable(admin).call{value: address(this).balance}("");
        require(success, "Transfer failed");
    }

    function pause() external onlyAdmin {
        _pause();
    }

    function unpause() external onlyAdmin {
        _unpause();
    }

    // ═══════════════════════════════════════════════════════════
    // VIEW FUNCTIONS
    // ═══════════════════════════════════════════════════════════
    function getCase(uint256 _caseId) external view caseExists(_caseId) returns (
        address client,
        string memory title,
        CaseStatus status,
        uint256 budget,
        uint256 spent,
        address investigator,
        string[] memory evidence
    ) {
        Case storage c = cases[_caseId];
        return (
            c.client,
            c.title,
            c.status,
            c.budget,
            c.spent,
            c.assignedInvestigator,
            c.evidenceHashes
        );
    }

    function getClientCases(address _client) external view returns (uint256[] memory) {
        return clientCases[_client];
    }

    function getCaseCount() external view returns (uint256) {
        return caseCounter;
    }

    // ═══════════════════════════════════════════════════════════
    // UPGRADE AUTHORIZATION
    // ═══════════════════════════════════════════════════════════
    function _authorizeUpgrade(address newImplementation) internal override onlyRole(UPGRADER_ROLE) {}

    receive() external payable {
        // Accept ETH deposits
    }
}
