    ) -> Result<()> {
        let case_account = &mut ctx.accounts.case_account;
        require!(
            ctx.accounts.operator.key() == case_account.assigned_investigator.unwrap_or_default() ||
            ctx.accounts.config.admin == ctx.accounts.operator.key(),
            ErrorCode::Unauthorized
        );

        case_account.status = new_status;
        case_account.updated_at = Clock::get()?.unix_timestamp;

        Ok(())
    }

