    // ═══════════════════════════════════════════════════════════
    pub fn emergency_withdraw(ctx: Context<EmergencyWithdraw>) -> Result<()> {
        let config = &ctx.accounts.config;
        require!(
            ctx.accounts.admin.key() == config.admin,
            ErrorCode::Unauthorized
        );
        require!(
            config.emergency_withdrawal_enabled,
            ErrorCode::EmergencyWithdrawalDisabled
        );

        let balance = ctx.accounts.vault.lamports();
        **ctx.accounts.vault.try_borrow_mut_lamports()? -= balance;
        **ctx.accounts.admin.try_borrow_mut_lamports()? += balance;

        Ok(())
    }

