            'contract_type': ContractType.CRM_V2,
            'chain': 'base',
            'name': 'RugMuncher CRM 2.0',
            'symbol': None,
            'admin_address': None,
            'operator_addresses': [],
            'fee_recipient': None,
            'platform_fee_bps': 250,  # 2.5%
            'require_multisig': False,
            'multisig_threshold': 1,
            'multisig_signers': [],
            'emergency_withdrawal_enabled': True,
            'pause_functionality': True,
            'upgradeable': True,
            'total_supply': None,
            'mintable': False,
            'burnable': False,
            'metadata_uri': None,
        }

    def on_chain(self, chain: str):
        """Set deployment chain"""
        if chain not in ['base', 'solana']:
            raise ValueError(f"Unsupported chain: {chain}")
        self.config['chain'] = chain
        return self

    def with_admin(self, address: str):
        """Set admin address"""
        self.config['admin_address'] = address
        return self

    def with_operators(self, addresses: List[str]):
        """Set operator addresses"""
        self.config['operator_addresses'] = addresses
        return self

    def with_fee_recipient(self, address: str):
        """Set fee recipient"""
        self.config['fee_recipient'] = address
        return self

    def with_platform_fee(self, basis_points: int):
        """Set platform fee in basis points (100 = 1%)"""
        self.config['platform_fee_bps'] = basis_points
        return self

    def with_multisig(self, threshold: int, signers: List[str]):
        """Enable and configure multi-sig"""
        self.config['require_multisig'] = True
        self.config['multisig_threshold'] = threshold
        self.config['multisig_signers'] = signers
        return self

    def with_emergency_controls(self, enabled: bool = True):
        """Enable emergency withdrawal"""
        self.config['emergency_withdrawal_enabled'] = enabled
        return self

    def upgradeable(self, enabled: bool = True):
        """Set upgradeability"""
        self.config['upgradeable'] = enabled
        return self

    def build(self) -> DeploymentConfig:
        """Build and validate configuration"""
        if not self.config['admin_address']:
            raise ValueError("Admin address is required")
        if not self.config['fee_recipient']:
            raise ValueError("Fee recipient is required")

        return DeploymentConfig(**self.config)

# ═══════════════════════════════════════════════════════════
# CLI INTERFACE
# ═══════════════════════════════════════════════════════════

def main():
    """CLI for contract deployment"""
    print("="*70)
    print("🚀 RugMuncher Contract Deployer")
    print("="*70)
    print()

    print("Supported Chains: Base (Ethereum L2), Solana")
    print("Supported Contracts: CRM 2.0")
    print()

    print("Usage:")
    print("  from rugmuncher_contract_deployer import ContractDeployer, CRMConfigBuilder")
    print()
    print("  # Build configuration")
    print("  config = (CRMConfigBuilder()")
    print("      .on_chain('base')")
    print("      .with_admin('0x...')")
    print("      .with_platform_fee(250)  # 2.5%")
    print("      .with_multisig(2, ['0x...', '0x...', '0x...'])")
    print("      .build())")
    print()
    print("  # Request deployment")
    print("  deployer = ContractDeployer(wallet_vault)")
    print("  deployment_id = deployer.request_deployment(config)")
    print()
    print("  # Approve and deploy (requires human approval)")
    print("  result = deployer.approve_deployment(deployment_id, 'admin', wallet_id)")


if __name__ == '__main__':
    main()
"}

