class ContractDeployer:
    """Deploy smart contracts to Base or Solana with human oversight"""

    def __init__(self, wallet_vault, deployment_storage: str = "deployments.json"):
        self.wallet_vault = wallet_vault
        self.deployment_storage = deployment_storage
        self.deployments: List[Dict] = []
        self.pending_deployments: List[Dict] = []
        self.load_deployments()

    def load_deployments(self):
        """Load deployment history"""
        if os.path.exists(self.deployment_storage):
            with open(self.deployment_storage, 'r') as f:
                data = json.load(f)
                self.deployments = data.get('deployments', [])
                self.pending_deployments = data.get('pending', [])

    def save_deployments(self):
        """Save deployment history"""
        with open(self.deployment_storage, 'w') as f:
            json.dump({
                'deployments': self.deployments,
                'pending': self.pending_deployments,
            }, f, indent=2, default=str)

    def request_deployment(self, config: DeploymentConfig, requested_by: str = "system") -> str:
        """Request contract deployment with human oversight"""

        deployment_id = secrets.token_hex(16)

        deployment = {
            'id': deployment_id,
            'config': asdict(config),
            'status': DeploymentStatus.PENDING_APPROVAL.value,
            'chain': config.chain,
            'contract_type': config.contract_type.value,
            'contract_address': None,
            'deployer_address': None,
            'transaction_hash': None,
            'requested_at': datetime.now().isoformat(),
            'approved_at': None,
            'deployed_at': None,
            'requested_by': requested_by,
            'approved_by': None,
            'gas_used': None,
            'cost_native': None,
            'cost_usd': None,
        }

        self.pending_deployments.append(deployment)
        self.save_deployments()

        logger.info(f"Deployment requested: {deployment_id} - {config.contract_type.value} on {config.chain}")

        return deployment_id

    def approve_deployment(self, deployment_id: str, approved_by: str, 
                          wallet_id: str) -> Dict:
        """Approve and execute deployment"""

        # Find deployment
        deployment = None
        for d in self.pending_deployments:
            if d['id'] == deployment_id:
                deployment = d
                break

        if not deployment:
            raise ValueError(f"Deployment {deployment_id} not found")

        if deployment['status'] != DeploymentStatus.PENDING_APPROVAL.value:
            raise ValueError(f"Deployment already {deployment['status']}")

        # Get wallet
        wallet = self.wallet_vault.get_wallet(wallet_id)
        if not wallet:
            raise ValueError(f"Wallet {wallet_id} not found")

        # Decrypt private key (requires approval)
        decrypt_result = self.wallet_vault.decrypt_private_key(wallet_id)
        if decrypt_result.startswith("PENDING_APPROVAL"):
            return {
                'status': 'waiting_approval',
                'message': 'Private key export requires separate approval',
                'approval_id': decrypt_result.split(":")[1],
            }

        # Execute deployment
        config = DeploymentConfig(**deployment['config'])

        try:
            if config.chain == 'base':
                result = self._deploy_base_contract(config, wallet, decrypt_result)
            elif config.chain == 'solana':
                result = self._deploy_solana_contract(config, wallet, decrypt_result)
            else:
                raise ValueError(f"Unsupported chain: {config.chain}")

            # Update deployment record
            deployment['status'] = DeploymentStatus.DEPLOYED.value
            deployment['contract_address'] = result['address']
            deployment['transaction_hash'] = result['tx_hash']
            deployment['deployed_at'] = datetime.now().isoformat()
            deployment['approved_by'] = approved_by
            deployment['approved_at'] = datetime.now().isoformat()
            deployment['gas_used'] = result.get('gas_used')
            deployment['cost_native'] = result.get('cost')
            deployment['explorer_url'] = result.get('explorer_url')

            # Move to completed
            self.deployments.append(deployment)
            self.pending_deployments = [d for d in self.pending_deployments if d['id'] != deployment_id]
            self.save_deployments()

            logger.info(f"Deployment complete: {result['address']}")

            return {
                'status': 'deployed',
                'deployment_id': deployment_id,
                'contract_address': result['address'],
                'explorer_url': result.get('explorer_url'),
            }

        except Exception as e:
            deployment['status'] = DeploymentStatus.FAILED.value
            self.save_deployments()
            logger.error(f"Deployment failed: {e}")
            raise

    def _deploy_base_contract(self, config: DeploymentConfig, wallet, private_key: str) -> Dict:
        """Deploy contract to Base"""
        try:
