                'cost': 0.005,
                'explorer_url': f'https://solscan.io/account/{secrets.token_hex(32)}',
                'note': 'SIMULATED - Install solana-py for real deployment',
            }

    def get_deployment_status(self, deployment_id: str) -> Optional[Dict]:
        """Get status of a deployment"""
        for d in self.deployments + self.pending_deployments:
            if d['id'] == deployment_id:
                return d
        return None

    def get_pending_deployments(self) -> List[Dict]:
        """Get all pending deployments"""
        return self.pending_deployments

    def export_contract_source(self, contract_type: ContractType, chain: str, 
                               output_dir: str = "contracts"):
        """Export contract source code to file"""
        os.makedirs(output_dir, exist_ok=True)

        if contract_type == ContractType.CRM_V2:
            if chain == 'base':
                filename = f"{output_dir}/CRM_V2_Base.sol"
                source = CRM_V2_BASE_CONTRACT
            elif chain == 'solana':
                filename = f"{output_dir}/CRM_V2_Solana.rs"
                source = CRM_V2_SOLANA_PROGRAM
            else:
                raise ValueError(f"Unsupported chain: {chain}")
        else:
            raise ValueError(f"Unsupported contract type: {contract_type}")

        with open(filename, 'w') as f:
            f.write(source)

        logger.info(f"Exported contract source: {filename}")
        return filename

