            errors.append("Admin address is required")

        if ContractFeature.TAXATION in self.features:
            total_tax = (self.tax_config.buy_tax_bps + 
                        self.tax_config.sell_tax_bps + 
                        self.tax_config.transfer_tax_bps)
            if total_tax > self.security_config.max_tax_limit_bps:
                errors.append(f"Total tax ({total_tax} bps) exceeds max limit ({self.security_config.max_tax_limit_bps} bps)")

            # Validate tax distribution adds up to 100%
            total_share = (self.tax_config.liquidity_share_bps + 
                          self.tax_config.marketing_share_bps +
                          self.tax_config.development_share_bps +
                          self.tax_config.reflection_share_bps +
                          self.tax_config.burn_share_bps)
            if total_share != 10000 and total_share != 0:
                errors.append(f"Tax distribution must total 10000 bps (100%), got {total_share}")

        if errors:
            raise ValueError(f"Configuration errors: {', '.join(errors)}")

        return True

