def generate_solana_token_program(config: CustomTokenConfig) -> str:
    """Generate customizable SPL token program for Solana"""

    features = config.features
    tax = config.tax_config
    blacklist = config.blacklist_config
    whitelist = config.whitelist_config
    anti_whale = config.anti_whale_config
    security = config.security_config
    token = config.tokenomics

    program = f'''
use anchor_lang::prelude::*;
use anchor_spl::token::{{self, Token, TokenAccount, Mint, Transfer, MintTo, Burn}};
use anchor_spl::associated_token::AssociatedToken;

// ═══════════════════════════════════════════════════════════
// {token.name} - Customizable SPL Token
// Chain: Solana
// Features: {', '.join(f.value for f in features)}
// ═══════════════════════════════════════════════════════════

declare_id!("{token.symbol}xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx");

#[program]
pub mod customizable_token {{
    use super::*;

    // ═══════════════════════════════════════════════════════════
    // CONSTANTS
    // ═══════════════════════════════════════════════════════════
    pub const DECIMALS: u8 = {token.decimals};
    pub const TOTAL_SUPPLY: u64 = {token.total_supply}u64 * 10u64.pow(DECIMALS as u32);

    // Tax limits (basis points)
    pub const MAX_TAX_BPS: u16 = {security.max_tax_limit_bps};
    pub const TAX_CHANGE_DELAY: i64 = {security.tax_change_delay} as i64;

    // ═══════════════════════════════════════════════════════════
    // INITIALIZATION
    // ═══════════════════════════════════════════════════════════
    pub fn initialize(
        ctx: Context<Initialize>,
        name: String,
        symbol: String,
        uri: String,
    ) -> Result<()> {{
        let config = &mut ctx.accounts.config;
        let mint = &ctx.accounts.mint;

        config.admin = ctx.accounts.admin.key();
        config.mint = mint.key();
        config.name = name;
        config.symbol = symbol;
        config.uri = uri;
        config.decimals = DECIMALS;
        config.total_supply = TOTAL_SUPPLY;
        config.initialized_at = Clock::get()?.unix_timestamp;
        config.paused = false;

        // Initialize tax settings
        let tax = &mut ctx.accounts.tax_config;
        tax.buy_tax_bps = {tax.buy_tax_bps};
        tax.sell_tax_bps = {tax.sell_tax_bps};
        tax.transfer_tax_bps = {tax.transfer_tax_bps};
        tax.liquidity_share_bps = {tax.liquidity_share_bps};
        tax.marketing_share_bps = {tax.marketing_share_bps};
        tax.development_share_bps = {tax.development_share_bps};
        tax.burn_share_bps = {tax.burn_share_bps};
        tax.reflection_share_bps = {tax.reflection_share_bps};
        tax.enabled = {'true' if tax.enabled else 'false'};
        tax.last_change = Clock::get()?.unix_timestamp;

        // Initialize wallets
        tax.marketing_wallet = {f'"{tax.marketing_wallet}".parse().unwrap()' if tax.marketing_wallet else "ctx.accounts.admin.key()"};
        tax.development_wallet = {f'"{tax.development_wallet}".parse().unwrap()' if tax.development_wallet else "ctx.accounts.admin.key()"};

        // Initialize security settings
        let security = &mut ctx.accounts.security_config;
        security.can_mint = {'true' if security.can_mint else 'false'};
        security.can_burn = {'true' if security.can_burn else 'false'};
        security.can_modify_taxes = {'true' if security.can_modify_taxes else 'false'};
        security.can_modify_blacklist = {'true' if security.can_modify_blacklist else 'false'};
        security.time_lock_delay = {security.time_lock_delay} as i64;

        // Initialize anti-whale settings
        let limits = &mut ctx.accounts.limit_config;
        limits.max_wallet_percent = {int(anti_whale.max_wallet_percent * 100)};  // Basis points
        limits.max_transaction_percent = {int(anti_whale.max_transaction_percent * 100)};
        limits.max_wallet_amount = (TOTAL_SUPPLY as u128 * limits.max_wallet_percent as u128 / 10000) as u64;
        limits.max_transaction_amount = (TOTAL_SUPPLY as u128 * limits.max_transaction_percent as u128 / 10000) as u64;
        limits.enabled = {'true' if anti_whale.enabled else 'false'};
        limits.cooldown_seconds = {anti_whale.cooldown_seconds};

        // Mint total supply to admin
        token::mint_to(
            CpiContext::new(
                ctx.accounts.token_program.to_account_info(),
                MintTo {{
                    mint: ctx.accounts.mint.to_account_info(),
                    to: ctx.accounts.admin_token_account.to_account_info(),
                    authority: ctx.accounts.mint_authority.to_account_info(),
                }},
            ),
            TOTAL_SUPPLY,
        )?;

        // Mark admin as whitelisted and limit exempt
        let whitelist = &mut ctx.accounts.whitelist;
        whitelist.whitelisted.push(ctx.accounts.admin.key());
        whitelist.limit_exempt.push(ctx.accounts.admin.key());

        emit!(TokenInitialized {{
            mint: mint.key(),
            admin: ctx.accounts.admin.key(),
            total_supply: TOTAL_SUPPLY,
        }});

        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // TRANSFER WITH TAX
    // ═══════════════════════════════════════════════════════════
    pub fn transfer_with_tax(
        ctx: Context<TransferWithTax>,
        amount: u64,
    ) -> Result<()> {{
        let config = &ctx.accounts.config;
        let tax_config = &ctx.accounts.tax_config;
        let blacklist = &ctx.accounts.blacklist;
        let whitelist = &ctx.accounts.whitelist;
        let limits = &ctx.accounts.limit_config;

        require!(!config.paused, ErrorCode::ContractPaused);

        let from = ctx.accounts.from.key();
        let to = ctx.accounts.to.key();

        // Blacklist check
        require!(
            !blacklist.blacklisted.contains(&from) && !blacklist.blacklisted.contains(&to),
            ErrorCode::Blacklisted
        );

        // Anti-whale checks
        if (limits.enabled && !whitelist.limit_exempt.contains(&to)) {{
            let recipient_balance = ctx.accounts.to_token_account.amount;
            require!(
                (recipient_balance as u128 + amount as u128) <= limits.max_wallet_amount as u128,
                ErrorCode::MaxWalletExceeded
            );
        }}

        if (limits.enabled && !whitelist.limit_exempt.contains(&from)) {{
            require!(
                amount <= limits.max_transaction_amount,
                ErrorCode::MaxTransactionExceeded
            );
        }}

        // Cooldown check
        if (limits.cooldown_seconds > 0 && !whitelist.limit_exempt.contains(&from)) {{
            let last_tx = ctx.accounts.sender_state.last_transaction_time;
            let current_time = Clock::get()?.unix_timestamp;
            require!(
                current_time >= last_tx + limits.cooldown_seconds,
                ErrorCode::CooldownActive
            );
            ctx.accounts.sender_state.last_transaction_time = current_time;
        }}

        // Calculate tax
        let mut tax_amount: u64 = 0;
        let mut tax_rate: u16 = 0;

        if (tax_config.enabled && 
            !whitelist.whitelisted.contains(&from) && 
            !whitelist.whitelisted.contains(&to)) {{

            // Determine if buy/sell/transfer (simplified - would check DEX accounts)
            tax_rate = tax_config.transfer_tax_bps;
            tax_amount = ((amount as u128 * tax_rate as u128) / 10000) as u64;
        }}

        let transfer_amount = amount - tax_amount;

        // Transfer to recipient
        token::transfer(
            CpiContext::new(
                ctx.accounts.token_program.to_account_info(),
                Transfer {{
                    from: ctx.accounts.from_token_account.to_account_info(),
                    to: ctx.accounts.to_token_account.to_account_info(),
                    authority: ctx.accounts.from.to_account_info(),
                }},
            ),
            transfer_amount,
        )?;

        // Handle tax distribution
        if (tax_amount > 0) {{
            // Transfer tax to contract
            token::transfer(
                CpiContext::new(
                    ctx.accounts.token_program.to_account_info(),
                    Transfer {{
                        from: ctx.accounts.from_token_account.to_account_info(),
                        to: ctx.accounts.tax_vault.to_account_info(),
                        authority: ctx.accounts.from.to_account_info(),
                    }},
                ),
                tax_amount,
            )?;

            emit!(TaxCollected {{
                from,
                amount: tax_amount,
                rate_bps: tax_rate,
            }});
        }}

        emit!(TransferWithTaxEvent {{
            from,
            to,
            amount: transfer_amount,
            tax: tax_amount,
        }});

        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // DISTRIBUTE TAXES (Admin only)
    // ═══════════════════════════════════════════════════════════
    pub fn distribute_taxes(ctx: Context<DistributeTaxes>) -> Result<()> {{
        let tax_config = &ctx.accounts.tax_config;
        let tax_vault_balance = ctx.accounts.tax_vault.amount;

        require!(tax_vault_balance > 0, ErrorCode::NoTaxToDistribute);

        let total_shares = tax_config.liquidity_share_bps + 
                          tax_config.marketing_share_bps + 
                          tax_config.development_share_bps +
                          tax_config.burn_share_bps +
                          tax_config.reflection_share_bps;

        require!(total_shares > 0, ErrorCode::InvalidTaxDistribution);

        // Calculate distribution amounts
        let marketing_amount = ((tax_vault_balance as u128 * tax_config.marketing_share_bps as u128) / total_shares as u128) as u64;
        let development_amount = ((tax_vault_balance as u128 * tax_config.development_share_bps as u128) / total_shares as u128) as u64;
        let burn_amount = ((tax_vault_balance as u128 * tax_config.burn_share_bps as u128) / total_shares as u128) as u64;

        let seeds = &[b"tax_vault".as_ref(), &[ctx.bumps.tax_vault]];
        let signer = &[&seeds[..]];

        // Transfer to marketing
        if (marketing_amount > 0) {{
            token::transfer(
                CpiContext::new_with_signer(
                    ctx.accounts.token_program.to_account_info(),
                    Transfer {{
                        from: ctx.accounts.tax_vault.to_account_info(),
                        to: ctx.accounts.marketing_wallet.to_account_info(),
                        authority: ctx.accounts.tax_vault.to_account_info(),
                    }},
                    signer,
                ),
                marketing_amount,
            )?;
        }}

        // Transfer to development
        if (development_amount > 0) {{
            token::transfer(
                CpiContext::new_with_signer(
                    ctx.accounts.token_program.to_account_info(),
                    Transfer {{
                        from: ctx.accounts.tax_vault.to_account_info(),
                        to: ctx.accounts.development_wallet.to_account_info(),
                        authority: ctx.accounts.tax_vault.to_account_info(),
                    }},
                    signer,
                ),
                development_amount,
            )?;
        }}

        // Burn portion
        if (burn_amount > 0) {{
            token::burn(
                CpiContext::new_with_signer(
                    ctx.accounts.token_program.to_account_info(),
                    Burn {{
                        mint: ctx.accounts.mint.to_account_info(),
                        from: ctx.accounts.tax_vault.to_account_info(),
                        authority: ctx.accounts.tax_vault.to_account_info(),
                    }},
                    signer,
                ),
                burn_amount,
            )?;
        }}

        emit!(TaxesDistributed {{
            marketing: marketing_amount,
            development: development_amount,
            burned: burn_amount,
        }});

        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // BLACKLIST MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    pub fn add_to_blacklist(
        ctx: Context<BlacklistManagement>,
        account: Pubkey,
    ) -> Result<()> {{
        let security = &ctx.accounts.security_config;
        let blacklist = &mut ctx.accounts.blacklist;

        require!(security.can_modify_blacklist, ErrorCode::BlacklistModificationsDisabled);
        require!(!blacklist.blacklisted.contains(&account), ErrorCode::AlreadyBlacklisted);

        blacklist.blacklisted.push(account);

        emit!(Blacklisted {{ account }});
        Ok(())
    }}

    pub fn remove_from_blacklist(
        ctx: Context<BlacklistManagement>,
        account: Pubkey,
    ) -> Result<()> {{
        let security = &ctx.accounts.security_config;
        let blacklist = &mut ctx.accounts.blacklist;

        require!(security.can_modify_blacklist, ErrorCode::BlacklistModificationsDisabled);

        if let Some(pos) = blacklist.blacklisted.iter().position(|&x| x == account) {{
            blacklist.blacklisted.remove(pos);
        }}

        emit!(Unblacklisted {{ account }});
        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // WHITELIST MANAGEMENT
    // ═══════════════════════════════════════════════════════════
    pub fn set_whitelisted(
        ctx: Context<WhitelistManagement>,
        account: Pubkey,
        whitelisted: bool,
        limit_exempt: bool,
    ) -> Result<()> {{
        let whitelist = &mut ctx.accounts.whitelist;

        if whitelisted {{
            if !whitelist.whitelisted.contains(&account) {{
                whitelist.whitelisted.push(account);
            }}
        }} else {{
            if let Some(pos) = whitelist.whitelisted.iter().position(|&x| x == account) {{
                whitelist.whitelisted.remove(pos);
            }}
        }}

        if limit_exempt {{
            if !whitelist.limit_exempt.contains(&account) {{
                whitelist.limit_exempt.push(account);
            }}
        }} else {{
            if let Some(pos) = whitelist.limit_exempt.iter().position(|&x| x == account) {{
                whitelist.limit_exempt.remove(pos);
            }}
        }}

        emit!(WhitelistUpdated {{ account, whitelisted, limit_exempt }});
        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // TAX CONFIGURATION
    // ═══════════════════════════════════════════════════════════
    pub fn set_tax_rates(
        ctx: Context<TaxConfiguration>,
        buy_tax_bps: u16,
        sell_tax_bps: u16,
        transfer_tax_bps: u16,
    ) -> Result<()> {{
        let security = &ctx.accounts.security_config;
        let tax_config = &mut ctx.accounts.tax_config;

        require!(security.can_modify_taxes, ErrorCode::TaxModificationsDisabled);

        let current_time = Clock::get()?.unix_timestamp;
        require!(
            current_time >= tax_config.last_change + TAX_CHANGE_DELAY,
            ErrorCode::TaxChangeDelayActive
        );

        require!(buy_tax_bps <= MAX_TAX_BPS, ErrorCode::TaxExceedsLimit);
        require!(sell_tax_bps <= MAX_TAX_BPS, ErrorCode::TaxExceedsLimit);
        require!(transfer_tax_bps <= MAX_TAX_BPS, ErrorCode::TaxExceedsLimit);

        tax_config.buy_tax_bps = buy_tax_bps;
        tax_config.sell_tax_bps = sell_tax_bps;
        tax_config.transfer_tax_bps = transfer_tax_bps;
        tax_config.last_change = current_time;

        emit!(TaxRatesUpdated {{
            buy_tax_bps,
            sell_tax_bps,
            transfer_tax_bps,
        }});

        Ok(())
    }}

    pub fn set_tax_distribution(
        ctx: Context<TaxConfiguration>,
        liquidity_share_bps: u16,
        marketing_share_bps: u16,
        development_share_bps: u16,
        burn_share_bps: u16,
        reflection_share_bps: u16,
    ) -> Result<()> {{
        let security = &ctx.accounts.security_config;
        let tax_config = &mut ctx.accounts.tax_config;

        require!(security.can_modify_taxes, ErrorCode::TaxModificationsDisabled);

        let total = liquidity_share_bps + marketing_share_bps + development_share_bps + 
                   burn_share_bps + reflection_share_bps;
        require!(total == 10000, ErrorCode::InvalidTaxDistribution);

        tax_config.liquidity_share_bps = liquidity_share_bps;
        tax_config.marketing_share_bps = marketing_share_bps;
        tax_config.development_share_bps = development_share_bps;
        tax_config.burn_share_bps = burn_share_bps;
        tax_config.reflection_share_bps = reflection_share_bps;

        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // LIMIT CONFIGURATION
    // ═══════════════════════════════════════════════════════════
    pub fn set_limits(
        ctx: Context<LimitConfiguration>,
        max_wallet_percent: u16,  // Basis points
        max_transaction_percent: u16,
        enabled: bool,
    ) -> Result<()> {{
        let limits = &mut ctx.accounts.limit_config;

        require!(max_wallet_percent >= 100, ErrorCode::LimitTooLow);  // Min 1%
        require!(max_transaction_percent >= 50, ErrorCode::LimitTooLow);  // Min 0.5%

        limits.max_wallet_percent = max_wallet_percent;
        limits.max_transaction_percent = max_transaction_percent;
        limits.max_wallet_amount = (TOTAL_SUPPLY as u128 * max_wallet_percent as u128 / 10000) as u64;
        limits.max_transaction_amount = (TOTAL_SUPPLY as u128 * max_transaction_percent as u128 / 10000) as u64;
        limits.enabled = enabled;

        emit!(LimitsUpdated {{
            max_wallet_percent,
            max_transaction_percent,
            enabled,
        }});

        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // MINTING
    // ═══════════════════════════════════════════════════════════
    pub fn mint_tokens(
        ctx: Context<MintTokens>,
        amount: u64,
    ) -> Result<()> {{
        let security = &ctx.accounts.security_config;
        require!(security.can_mint, ErrorCode::MintingDisabled);

        token::mint_to(
            CpiContext::new(
                ctx.accounts.token_program.to_account_info(),
                MintTo {{
                    mint: ctx.accounts.mint.to_account_info(),
                    to: ctx.accounts.to_token_account.to_account_info(),
                    authority: ctx.accounts.mint_authority.to_account_info(),
                }},
            ),
            amount,
        )?;

        emit!(TokensMinted {{
            to: ctx.accounts.to.key(),
            amount,
        }});

        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // BURNING
    // ═══════════════════════════════════════════════════════════
    pub fn burn_tokens(
        ctx: Context<BurnTokens>,
        amount: u64,
    ) -> Result<()> {{
        let security = &ctx.accounts.security_config;
        require!(security.can_burn, ErrorCode::BurningDisabled);

        token::burn(
            CpiContext::new(
                ctx.accounts.token_program.to_account_info(),
                Burn {{
                    mint: ctx.accounts.mint.to_account_info(),
                    from: ctx.accounts.token_account.to_account_info(),
                    authority: ctx.accounts.authority.to_account_info(),
                }},
            ),
            amount,
        )?;

        emit!(TokensBurned {{
            from: ctx.accounts.authority.key(),
            amount,
        }});

        Ok(())
    }}

    // ═══════════════════════════════════════════════════════════
    // PAUSE
    // ═══════════════════════════════════════════════════════════
    pub fn pause(ctx: Context<AdminOnly>) -> Result<()> {{
        ctx.accounts.config.paused = true;
        emit!(Paused {{}});
        Ok(())
    }}

    pub fn unpause(ctx: Context<AdminOnly>) -> Result<()> {{
        ctx.accounts.config.paused = false;
        emit!(Unpaused {{}});
        Ok(())
    }}
}}

