# ═══════════════════════════════════════════════════════════
# CONTRACT BUILDER
# ═══════════════════════════════════════════════════════════

class CustomTokenBuilder:
    """Builder for customizable token contracts"""

    def __init__(self):
        self.config = CustomTokenConfig()

    def on_chain(self, chain: str):
        if chain not in ['base', 'solana']:
            raise ValueError(f"Unsupported chain: {chain}")
        self.config.chain = chain
        return self

    def with_name(self, name: str, symbol: str):
        self.config.tokenomics.name = name
        self.config.tokenomics.symbol = symbol
        return self

    def with_supply(self, total_supply: int, decimals: int = 18):
        self.config.tokenomics.total_supply = total_supply
        self.config.tokenomics.decimals = decimals
        return self

    def with_taxes(self, buy: float = 0, sell: float = 0, transfer: float = 0):
        """Set taxes as percentages (e.g., 2.5 for 2.5%)"""
        self.config.tax_config.buy_tax_bps = int(buy * 100)
        self.config.tax_config.sell_tax_bps = int(sell * 100)
        self.config.tax_config.transfer_tax_bps = int(transfer * 100)
        self.config.tax_config.enabled = (buy > 0 or sell > 0 or transfer > 0)
        return self

    def with_tax_distribution(self, liquidity: float = 0, marketing: float = 0, 
                               development: float = 0, burn: float = 0, 
                               reflection: float = 0):
        """Distribute tax as percentages (must total 100%)"""
        self.config.tax_config.liquidity_share_bps = int(liquidity * 100)
        self.config.tax_config.marketing_share_bps = int(marketing * 100)
        self.config.tax_config.development_share_bps = int(development * 100)
        self.config.tax_config.burn_share_bps = int(burn * 100)
        self.config.tax_config.reflection_share_bps = int(reflection * 100)
        return self

    def with_fee_recipients(self, marketing: Optional[str] = None, 
                           development: Optional[str] = None,
                           liquidity: Optional[str] = None):
        self.config.tax_config.marketing_wallet = marketing
        self.config.tax_config.development_wallet = development
        self.config.tax_config.liquidity_wallet = liquidity
        return self

    def with_blacklist(self, enabled: bool = True, can_unblacklist: bool = True,
                       permanent: bool = False):
        if enabled:
            self.config.features.append(ContractFeature.BLACKLIST)
        self.config.blacklist_config.enabled = enabled
        self.config.blacklist_config.can_unblacklist = can_unblacklist
        self.config.blacklist_config.permanent_blacklist = permanent
        return self

    def with_initial_blacklist(self, addresses: List[str]):
        self.config.blacklist_config.initial_blacklist = addresses
        return self

    def with_whitelist(self, enabled: bool = True):
        if enabled:
            self.config.features.append(ContractFeature.WHITELIST)
        self.config.whitelist_config.enabled = enabled
        return self

    def with_anti_whale(self, max_wallet_percent: float = 2.0,
                       max_tx_percent: float = 1.0,
                       cooldown_seconds: int = 0):
        self.config.features.append(ContractFeature.ANTI_WHALE)
        self.config.anti_whale_config.enabled = True
        self.config.anti_whale_config.max_wallet_percent = max_wallet_percent
        self.config.anti_whale_config.max_transaction_percent = max_tx_percent
        self.config.anti_whale_config.cooldown_enabled = cooldown_seconds > 0
        self.config.anti_whale_config.cooldown_seconds = cooldown_seconds
        return self

    def with_liquidity(self, enabled: bool = True, router: Optional[str] = None):
        self.config.features.append(ContractFeature.LIQUIDITY_POOL)
        self.config.liquidity_config.enabled = enabled
        self.config.liquidity_config.router_address = router
        return self

    def mintable(self, enabled: bool = True):
        if enabled:
            self.config.features.append(ContractFeature.MINTABLE)
        self.config.security_config.can_mint = enabled
        return self

    def burnable(self, enabled: bool = True):
        if enabled:
            self.config.features.append(ContractFeature.BURNABLE)
        self.config.security_config.can_burn = enabled
        return self

    def upgradeable(self, enabled: bool = True):
        if enabled:
            self.config.features.append(ContractFeature.UPGRADEABLE)
        return self

    def with_reflection(self, enabled: bool = True):
        if enabled:
            self.config.features.append(ContractFeature.REFLECTION)
        return self

    def with_admin(self, address: str):
        self.config.admin_address = address
        return self

    def with_max_tax_limit(self, percent: float):
        self.config.security_config.max_tax_limit_bps = int(percent * 100)
        return self

    def build(self) -> CustomTokenConfig:
        self.config.validate()
        return self.config

    def generate_contract(self) -> str:
        """Generate the contract source code"""
        self.config.validate()

        if self.config.chain == 'base':
            return generate_base_token_contract(self.config)
        elif self.config.chain == 'solana':
            return generate_solana_token_program(self.config)
        else:
            raise ValueError(f"Unsupported chain: {self.config.chain}")

# ═══════════════════════════════════════════════════════════
