# ═══════════════════════════════════════════════════════════

def main():
    print("="*70)
    print("🎨 RugMuncher Custom Token Contract Factory")
    print("="*70)
    print()
    print("Create fully customizable token contracts with:")
    print("  • Adjustable taxes (buy/sell/transfer)")
    print("  • Blacklist/whitelist functionality")
