    .with_tax_distribution(
        liquidity=50,     # 50% of tax to LP
        marketing=30,     # 30% to marketing
        development=10,   # 10% to dev
        burn=10           # 10% burned
    )
    .with_fee_recipients(
        marketing='0x...',
        development='0x...'
    )
    .with_blacklist(enabled=True)
    .with_anti_whale(max_wallet=2.0, max_tx=1.0)
