#!/usr/bin/env python3
"""
🎨 RugMuncher Custom Contract Factory
Fully customizable smart contracts for Base and Solana

Features:
- Adjustable taxes (buy/sell/transfer)
- Blacklist/whitelist functionality
- Mint/burn controls
- Fee recipients
- Trading controls
- All parameters configurable at deployment
"""

import os
import json
import secrets
from typing import Dict, List, Optional, Any, Union
from dataclasses import dataclass, field
from enum import Enum
from datetime import datetime

# ═══════════════════════════════════════════════════════════
# CONFIGURATION CLASSES
# ═══════════════════════════════════════════════════════════

class TaxType(Enum):
    BUY = "buy"
    SELL = "sell"
    TRANSFER = "transfer"

class ContractFeature(Enum):
    TAXATION = "taxation"
    BLACKLIST = "blacklist"
    WHITELIST = "whitelist"
    MINTABLE = "mintable"
    BURNABLE = "burnable"
    PAUSABLE = "pausable"
    UPGRADEABLE = "upgradeable"
    REFLECTION = "reflection"
    LIQUIDITY_POOL = "liquidity_pool"
    ANTI_WHALE = "anti_whale"
    TIME_LOCK = "time_lock"

@dataclass
class TaxConfig:
    """Tax configuration for token contracts"""
    enabled: bool = True
    buy_tax_bps: int = 0  # Basis points (100 = 1%)
    sell_tax_bps: int = 0
    transfer_tax_bps: int = 0

    # Fee distribution
    liquidity_share_bps: int = 0  # To LP
    marketing_share_bps: int = 0  # To marketing wallet
    development_share_bps: int = 0  # To dev wallet
    reflection_share_bps: int = 0  # To holders (reflection)
    burn_share_bps: int = 0  # Burned

    # Recipients
    liquidity_wallet: Optional[str] = None
    marketing_wallet: Optional[str] = None
    development_wallet: Optional[str] = None

    # Trading thresholds
    max_tax_amount: Optional[int] = None  # Max tokens per tax transaction
    min_tax_amount: int = 0

@dataclass
class BlacklistConfig:
    """Blacklist configuration"""
    enabled: bool = True
    can_blacklist: bool = True  # Admin can add to blacklist
    can_unblacklist: bool = True  # Admin can remove from blacklist
    permanent_blacklist: bool = False  # Once blacklisted, always blacklisted

    # Initial blacklisted addresses (bots, etc.)
    initial_blacklist: List[str] = field(default_factory=list)

    # Blacklist effects
    blocked_operations: List[str] = field(default_factory=lambda: ["transfer", "receive"])

@dataclass
class WhitelistConfig:
    """Whitelist configuration (fee exemptions)"""
    enabled: bool = True

    # Exempt from taxes
    tax_exempt_addresses: List[str] = field(default_factory=list)

    # Exempt from limits
    limit_exempt_addresses: List[str] = field(default_factory=list)

    # Initial whitelisted (team, liquidity, etc.)
    initial_whitelist: List[str] = field(default_factory=list)

@dataclass
class AntiWhaleConfig:
    """Anti-whale / max transaction limits"""
    enabled: bool = False
    max_wallet_percent: float = 2.0  # Max % of supply per wallet
    max_transaction_percent: float = 1.0  # Max % per transaction
    cooldown_enabled: bool = False
    cooldown_seconds: int = 60  # Time between transactions

@dataclass
class LiquidityConfig:
    """Auto-liquidity generation"""
    enabled: bool = False
    auto_liquidity_threshold: int = 1000  # Tokens to trigger LP addition
    liquidity_pair_token: str = "0x..."  # Usually WETH/WBNB
    router_address: Optional[str] = None

@dataclass
class TokenomicsConfig:
    """Token economics"""
    name: str = "RugMuncher Token"
    symbol: str = "RUG"
    decimals: int = 18
    total_supply: int = 1_000_000_000  # 1 billion

    # Distribution at launch
    team_allocation_percent: float = 10.0
    marketing_allocation_percent: float = 5.0
    liquidity_allocation_percent: float = 30.0
    public_sale_percent: float = 55.0

    # Vesting
    team_vesting_enabled: bool = True
    team_vesting_duration_months: int = 24
    team_vesting_cliff_months: int = 6

@dataclass
class SecurityConfig:
    """Security settings"""
    renounce_ownership_delay: Optional[int] = None  # Seconds before can renounce
    time_lock_delay: int = 86400  # 24 hours for admin actions

    # Function restrictions
    can_mint: bool = True
    can_burn: bool = True
    can_pause: bool = True
    can_modify_taxes: bool = True
    can_modify_blacklist: bool = True

    # Tax modification limits
    max_tax_limit_bps: int = 1000  # 10% max tax
    tax_change_delay: int = 3600  # 1 hour delay on tax changes

@dataclass
class CustomTokenConfig:
    """Complete customizable token configuration"""
    chain: str = "base"  # 'base' or 'solana'

    # Token info
    tokenomics: TokenomicsConfig = field(default_factory=TokenomicsConfig)

    # Features
    features: List[ContractFeature] = field(default_factory=lambda: [
        ContractFeature.TAXATION,
        ContractFeature.BLACKLIST,
        ContractFeature.WHITELIST,
        ContractFeature.PAUSABLE,
    ])

    # Tax settings
    tax_config: TaxConfig = field(default_factory=TaxConfig)

    # Blacklist settings
    blacklist_config: BlacklistConfig = field(default_factory=BlacklistConfig)

    # Whitelist settings
    whitelist_config: WhitelistConfig = field(default_factory=WhitelistConfig)

    # Anti-whale
    anti_whale_config: AntiWhaleConfig = field(default_factory=AntiWhaleConfig)

    # Liquidity
    liquidity_config: LiquidityConfig = field(default_factory=LiquidityConfig)

    # Security
    security_config: SecurityConfig = field(default_factory=SecurityConfig)

    # Admin
    admin_address: str = ""

    # Metadata
    metadata_uri: Optional[str] = None

    def validate(self):
        """Validate configuration"""
        errors = []

        if not self.admin_address:
            errors.append("Admin address is required")

        if ContractFeature.TAXATION in self.features:
            total_tax = (self.tax_config.buy_tax_bps + 
                        self.tax_config.sell_tax_bps + 
                        self.tax_config.transfer_tax_bps)
            if total_tax > self.security_config.max_tax_limit_bps:
                errors.append(f"Total tax ({total_tax} bps) exceeds max limit ({self.security_config.max_tax_limit_bps} bps)")

            # Validate tax distribution adds up to 100%
            total_share = (self.tax_config.liquidity_share_bps + 
                          self.tax_config.marketing_share_bps +
                          self.tax_config.development_share_bps +
                          self.tax_config.reflection_share_bps +
                          self.tax_config.burn_share_bps)
            if total_share != 10000 and total_share != 0:
                errors.append(f"Tax distribution must total 10000 bps (100%), got {total_share}")

        if errors:
            raise ValueError(f"Configuration errors: {', '.join(errors)}")

        return True

# ═══════════════════════════════════════════════════════════
# BASE CONTRACT TEMPLATES
# ═══════════════════════════════════════════════════════════

def generate_base_token_contract(config: CustomTokenConfig) -> str:
    """Generate customizable ERC20 token contract for Base"""

    features = config.features
    tax = config.tax_config
    blacklist = config.blacklist_config
    whitelist = config.whitelist_config
    anti_whale = config.anti_whale_config
    liquidity = config.liquidity_config
    security = config.security_config
    token = config.tokenomics

    # Build imports
    imports = [
        "// SPDX-License-Identifier: MIT",
        "pragma solidity ^0.8.19;",
        "",
        'import "@openzeppelin/contracts/token/ERC20/ERC20.sol";',
        'import "@openzeppelin/contracts/access/Ownable.sol";',
        'import "@openzeppelin/contracts/security/Pausable.sol";',
    ]

    if ContractFeature.UPGRADEABLE in features:
        imports.append('import "@openzeppelin/contracts/proxy/utils/UUPSUpgradeable.sol";')

    if liquidity.enabled:
        imports.append('import "@uniswap/v2-periphery/contracts/interfaces/IUniswapV2Router02.sol";')
        imports.append('import "@uniswap/v2-core/contracts/interfaces/IUniswapV2Factory.sol";')

    imports_str = "\n".join(imports)

    # Build contract header
    inheritances = ["ERC20", "Ownable", "Pausable"]
    if ContractFeature.UPGRADEABLE in features:
        inheritances.append("UUPSUpgradeable")

    inheritance_str = ", ".join(inheritances)

    contract = f'''
{imports_str}

/**
 * @title {token.name}
 * @symbol {token.symbol}
 * @dev Fully customizable token with optional taxation, blacklist, and security features
 * 
 * Configuration:
 * - Buy Tax: {tax.buy_tax_bps / 100}%
 * - Sell Tax: {tax.sell_tax_bps / 100}%
 * - Transfer Tax: {tax.transfer_tax_bps / 100}%
 * - Max Wallet: {anti_whale.max_wallet_percent}%
 * - Max Transaction: {anti_whale.max_transaction_percent}%
 * - Blacklist: {'Enabled' if blacklist.enabled else 'Disabled'}
 * - Whitelist: {'Enabled' if whitelist.enabled else 'Disabled'}
 */
contract {token.symbol}Token is {inheritance_str} {{

    // ═══════════════════════════════════════════════════════════
    // TOKEN INFO (Configurable)
    // ═══════════════════════════════════════════════════════════
    string private constant _NAME = "{token.name}";
    string private constant _SYMBOL = "{token.symbol}";
    uint8 private constant _DECIMALS = {token.decimals};
    uint256 private constant _TOTAL_SUPPLY = {token.total_supply} * 10**_DECIMALS;

    // ═══════════════════════════════════════════════════════════
    // TAX CONFIGURATION (Adjustable by admin within limits)
    // ═══════════════════════════════════════════════════════════
    struct TaxSettings {{
        uint16 buyTaxBps;           // Basis points (100 = 1%)
        uint16 sellTaxBps;
        uint16 transferTaxBps;
        uint16 liquidityShareBps;   // Of tax amount
        uint16 marketingShareBps;
        uint16 developmentShareBps;
        uint16 reflectionShareBps;
        uint16 burnShareBps;
        bool enabled;
    }}

    TaxSettings public taxSettings = TaxSettings({{
        buyTaxBps: {tax.buy_tax_bps},
        sellTaxBps: {tax.sell_tax_bps},
        transferTaxBps: {tax.transfer_tax_bps},
        liquidityShareBps: {tax.liquidity_share_bps},
        marketingShareBps: {tax.marketing_share_bps},
        developmentShareBps: {tax.development_share_bps},
        reflectionShareBps: {tax.reflection_share_bps},
        burnShareBps: {tax.burn_share_bps},
        enabled: {'true' if tax.enabled else 'false'}
    }});

    uint16 public constant MAX_TAX_LIMIT_BPS = {security.max_tax_limit_bps};  // 10% max
    uint256 public lastTaxChange;
    uint256 public constant TAX_CHANGE_DELAY = {security.tax_change_delay};  // 1 hour

    // Fee recipients
    address public liquidityWallet = {f'"{tax.liquidity_wallet}"' if tax.liquidity_wallet else "address(0)"};
    address public marketingWallet = {f'"{tax.marketing_wallet}"' if tax.marketing_wallet else "address(0)"};
    address public developmentWallet = {f'"{tax.development_wallet}"' if tax.development_wallet else "address(0)"};

    // ═══════════════════════════════════════════════════════════
    // BLACKLIST CONFIGURATION
    // ═══════════════════════════════════════════════════════════
'''

    if blacklist.enabled:
        contract += f'''
    mapping(address => bool) public blacklisted;
    bool public blacklistEnabled = {'true' if blacklist.enabled else 'false'};
    bool public canUnblacklist = {'true' if blacklist.can_unblacklist else 'false'};
    bool public permanentBlacklist = {'true' if blacklist.permanent_blacklist else 'false'};

    event Blacklisted(address indexed account);
    event Unblacklisted(address indexed account);
'''

    contract += f'''
    // ═══════════════════════════════════════════════════════════
    // WHITELIST CONFIGURATION (Fee exemptions)
    // ═══════════════════════════════════════════════════════════
'''

    if whitelist.enabled:
        contract += f'''
    mapping(address => bool) public isWhitelisted;  // Exempt from taxes
    mapping(address => bool) public isLimitExempt;  // Exempt from wallet/tx limits
    bool public whitelistEnabled = {'true' if whitelist.enabled else 'false'};
'''

    contract += f'''
    // ═══════════════════════════════════════════════════════════
    // ANTI-WHALE CONFIGURATION
    // ═══════════════════════════════════════════════════════════
'''

    if anti_whale.enabled:
        contract += f'''
    uint256 public maxWalletAmount = (_TOTAL_SUPPLY * {int(anti_whale.max_wallet_percent * 100)}) / 10000;  // {anti_whale.max_wallet_percent}%
    uint256 public maxTransactionAmount = (_TOTAL_SUPPLY * {int(anti_whale.max_transaction_percent * 100)}) / 10000;  // {anti_whale.max_transaction_percent}%
    bool public antiWhaleEnabled = {'true' if anti_whale.enabled else 'false'};

    mapping(address => uint256) private _lastTransactionTime;
    uint256 public constant COOLDOWN_SECONDS = {anti_whale.cooldown_seconds};
'''

    contract += f'''
    // ═══════════════════════════════════════════════════════════
    // LIQUIDITY CONFIGURATION
    // ═══════════════════════════════════════════════════════════
'''

    if liquidity.enabled:
        contract += f'''
    IUniswapV2Router02 public immutable uniswapV2Router;
    address public immutable uniswapV2Pair;
    bool public autoLiquidityEnabled = {'true' if liquidity.enabled else 'false'};
    uint256 public autoLiquidityThreshold = {liquidity.auto_liquidity_threshold} * 10**_DECIMALS;
    bool public swapping;

    modifier lockTheSwap {{
        swapping = true;
        _;
        swapping = false;
    }}
'''

    contract += f'''
    // ═══════════════════════════════════════════════════════════
    // REFLECTION CONFIGURATION
    // ═══════════════════════════════════════════════════════════
'''

    if ContractFeature.REFLECTION in features:
        contract += f'''
    uint256 public totalReflectionFees;
    mapping(address => uint256) public reflectionRewards;
'''

    contract += f'''
    // ═══════════════════════════════════════════════════════════
    // SECURITY CONFIGURATION
    // ═══════════════════════════════════════════════════════════
    bool public mintingEnabled = {'true' if security.can_mint and ContractFeature.MINTABLE in features else 'false'};
    bool public burningEnabled = {'true' if security.can_burn and ContractFeature.BURNABLE in features else 'false'};
    bool public taxModifiable = {'true' if security.can_modify_taxes else 'false'};
    bool public blacklistModifiable = {'true' if security.can_modify_blacklist else 'false'};

    uint256 public deployedAt;
    uint256 public constant TIME_LOCK_DELAY = {security.time_lock_delay};  // 24 hours

    mapping(bytes32 => uint256) public pendingActions;

    // ═══════════════════════════════════════════════════════════
    // EVENTS
    // ═══════════════════════════════════════════════════════════
    event TaxSettingsUpdated(uint16 buyTax, uint16 sellTax, uint16 transferTax);
    event FeeRecipientUpdated(string recipientType, address newAddress);
    event Whitelisted(address indexed account, bool status);
    event LimitsUpdated(uint256 maxWallet, uint256 maxTransaction);

    // ═══════════════════════════════════════════════════════════
    // CONSTRUCTOR
    // ═══════════════════════════════════════════════════════════
    constructor(
        address initialOwner'''

    if liquidity.enabled:
        contract += f''',
        address routerAddress'''

    contract += f'''
    ) ERC20(_NAME, _SYMBOL) Ownable(initialOwner) {{
        deployedAt = block.timestamp;

        // Mint total supply to deployer
        _mint(initialOwner, _TOTAL_SUPPLY);

'''

    if liquidity.enabled:
        contract += f'''
        // Initialize Uniswap
        IUniswapV2Router02 _uniswapV2Router = IUniswapV2Router02(routerAddress);
        uniswapV2Router = _uniswapV2Router;

        uniswapV2Pair = IUniswapV2Factory(_uniswapV2Router.factory())
            .createPair(address(this), _uniswapV2Router.WETH());

        // Exempt pair from taxes
        isWhitelisted[uniswapV2Pair] = true;
        isLimitExempt[uniswapV2Pair] = true;
'''

    if whitelist.enabled:
        contract += f'''
        // Whitelist initial addresses
'''
        for addr in whitelist.initial_whitelist:
            contract += f'''        isWhitelisted[{addr}] = true;
        isLimitExempt[{addr}] = true;
'''

    if blacklist.enabled and blacklist.initial_blacklist:
        contract += f'''
        // Blacklist initial addresses (bots, etc.)
'''
        for addr in blacklist.initial_blacklist:
            contract += f'''        blacklisted[{addr}] = true;
'''

    contract += f'''
        // Whitelist owner
        isWhitelisted[initialOwner] = true;
        isLimitExempt[initialOwner] = true;
    }}

    // ═══════════════════════════════════════════════════════════
    // MODIFIERS
    // ═══════════════════════════════════════════════════════════
'''

    if blacklist.enabled:
        contract += f'''
    modifier notBlacklisted(address account) {{
        require(!blacklisted[account] || !blacklistEnabled, "Address is blacklisted");
        _;
    }}
'''

    contract += f'''
    modifier timeLocked(bytes32 action) {{
        require(pendingActions[action] != 0, "Action not queued");
        require(block.timestamp >= pendingActions[action] + TIME_LOCK_DELAY, "Action time-locked");
        _;
        delete pendingActions[action];
    }}

    // ═══════════════════════════════════════════════════════════
    // TRANSFER LOGIC WITH TAXES
    // ═══════════════════════════════════════════════════════════
    function _update(
        address from,
        address to,
        uint256 amount
    ) internal virtual override whenNotPaused '''

    if blacklist.enabled:
        contract += f'''notBlacklisted(from) notBlacklisted(to) '''

    contract += f'''{{
        require(from != address(0), "ERC20: transfer from zero address");
        require(to != address(0), "ERC20: transfer to zero address");

'''

    if anti_whale.enabled:
        contract += f'''
        // Anti-whale checks
        if (antiWhaleEnabled && !isLimitExempt[to] && from != address(0)) {{
            require(balanceOf(to) + amount <= maxWalletAmount, "Exceeds max wallet");
        }}
        if (antiWhaleEnabled && !isLimitExempt[from] && to != address(0)) {{
            require(amount <= maxTransactionAmount, "Exceeds max transaction");
        }}

        // Cooldown
        if (COOLDOWN_SECONDS > 0 && !isLimitExempt[from]) {{
            require(
                block.timestamp >= _lastTransactionTime[from] + COOLDOWN_SECONDS,
                "Transaction cooldown active"
            );
            _lastTransactionTime[from] = block.timestamp;
        }}
'''

    contract += f'''
        // Calculate and apply taxes
        uint256 taxAmount = 0;
        if (taxSettings.enabled && !isWhitelisted[from] && !isWhitelisted[to]) {{
            uint16 taxRate = 0;

            // Determine tax type
            if (from == uniswapV2Pair) {{
                taxRate = taxSettings.buyTaxBps;  // Buy
            }} else if (to == uniswapV2Pair) {{
                taxRate = taxSettings.sellTaxBps;  // Sell
            }} else {{
                taxRate = taxSettings.transferTaxBps;  // Transfer
            }}

            taxAmount = (amount * taxRate) / 10000;
        }}

        uint256 sendAmount = amount - taxAmount;

'''

    if liquidity.enabled:
        contract += f'''
        // Handle liquidity generation
        if (
            autoLiquidityEnabled &&
            !swapping &&
            to == uniswapV2Pair &&
            taxAmount > 0
        ) {{
            _handleLiquidityAndTaxes(taxAmount);
        }}
'''

    contract += f'''
        super._update(from, to, sendAmount);

        if (taxAmount > 0) {{
            super._update(from, address(this), taxAmount);
            _distributeTaxes(taxAmount);
        }}
    }}

    function _distributeTaxes(uint256 taxAmount) internal {{
        if (taxAmount == 0) return;

        uint256 totalShares = taxSettings.liquidityShareBps + 
                              taxSettings.marketingShareBps + 
                              taxSettings.developmentShareBps +
                              taxSettings.reflectionShareBps +
                              taxSettings.burnShareBps;

        if (totalShares == 0) return;

'''

    if tax.marketing_share_bps > 0:
        contract += f'''
        // Marketing
        if (taxSettings.marketingShareBps > 0 && marketingWallet != address(0)) {{
            uint256 marketingAmount = (taxAmount * taxSettings.marketingShareBps) / totalShares;
            _transfer(address(this), marketingWallet, marketingAmount);
        }}
'''

    if tax.development_share_bps > 0:
        contract += f'''
        // Development
        if (taxSettings.developmentShareBps > 0 && developmentWallet != address(0)) {{
            uint256 devAmount = (taxAmount * taxSettings.developmentShareBps) / totalShares;
            _transfer(address(this), developmentWallet, devAmount);
        }}
'''

    if tax.burn_share_bps > 0:
        contract += f'''
        // Burn
        if (taxSettings.burnShareBps > 0 && burningEnabled) {{
            uint256 burnAmount = (taxAmount * taxSettings.burnShareBps) / totalShares;
            _burn(address(this), burnAmount);
        }}
'''

    if ContractFeature.REFLECTION in features and tax.reflection_share_bps > 0:
        contract += f'''
        // Reflection (simplified - would need proper distribution logic)
        if (taxSettings.reflectionShareBps > 0) {{
            uint256 reflectionAmount = (taxAmount * taxSettings.reflectionShareBps) / totalShares;
            totalReflectionFees += reflectionAmount;
            // Reflection distribution logic here
        }}
'''

    contract += f'''
    }}

'''

    if liquidity.enabled:
        contract += f'''
    function _handleLiquidityAndTaxes(uint256 taxAmount) internal lockTheSwap {{
        uint256 contractTokenBalance = balanceOf(address(this));

        if (contractTokenBalance >= autoLiquidityThreshold) {{
            uint256 liquidityAmount = (taxAmount * taxSettings.liquidityShareBps) / 10000;

            if (liquidityAmount > 0) {{
                _swapAndLiquify(liquidityAmount);
            }}
        }}
    }}

    function _swapAndLiquify(uint256 tokens) private {{
        uint256 half = tokens / 2;
        uint256 otherHalf = tokens - half;

        uint256 initialBalance = address(this).balance;

        _swapTokensForEth(half);

        uint256 newBalance = address(this).balance - initialBalance;

        _addLiquidity(otherHalf, newBalance);

        emit SwapAndLiquify(half, newBalance, otherHalf);
    }}

    function _swapTokensForEth(uint256 tokenAmount) private {{
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapV2Router.WETH();

        _approve(address(this), address(uniswapV2Router), tokenAmount);

        uniswapV2Router.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            0,
            path,
            address(this),
            block.timestamp
        );
    }}

    function _addLiquidity(uint256 tokenAmount, uint256 ethAmount) private {{
        _approve(address(this), address(uniswapV2Router), tokenAmount);

        uniswapV2Router.addLiquidityETH{{value: ethAmount}}(
            address(this),
            tokenAmount,
            0,
            0,
            liquidityWallet != address(0) ? liquidityWallet : owner(),
            block.timestamp
        );
    }}

    event SwapAndLiquify(uint256 tokensSwapped, uint256 ethReceived, uint256 tokensIntoLiquidity);
'''

    # Admin functions
    contract += f'''
    // ═══════════════════════════════════════════════════════════
    // ADMIN FUNCTIONS
    // ═══════════════════════════════════════════════════════════
'''

    if blacklist.enabled:
        contract += f'''
    // Blacklist management
    function addToBlacklist(address account) external onlyOwner {{
        require(blacklistModifiable, "Blacklist modifications disabled");
        require(!permanentBlacklist || !blacklisted[account], "Cannot modify permanent blacklist");
        blacklisted[account] = true;
        emit Blacklisted(account);
    }}

    function removeFromBlacklist(address account) external onlyOwner {{
        require(blacklistModifiable, "Blacklist modifications disabled");
        require(canUnblacklist, "Unblacklisting disabled");
        require(!permanentBlacklist, "Cannot modify permanent blacklist");
        blacklisted[account] = false;
        emit Unblacklisted(account);
    }}

    function setBlacklistEnabled(bool enabled) external onlyOwner {{
        blacklistEnabled = enabled;
    }}
'''

    if whitelist.enabled:
        contract += f'''
    // Whitelist management
    function setWhitelisted(address account, bool status) external onlyOwner {{
        isWhitelisted[account] = status;
        emit Whitelisted(account, status);
    }}

    function setLimitExempt(address account, bool status) external onlyOwner {{
        isLimitExempt[account] = status;
    }}
'''

    if security.can_modify_taxes:
        contract += f'''
    // Tax management
    function setTaxSettings(
        uint16 buyTax,
        uint16 sellTax,
        uint16 transferTax
    ) external onlyOwner {{
        require(taxModifiable, "Tax modifications disabled");
        require(block.timestamp >= lastTaxChange + TAX_CHANGE_DELAY, "Tax change delay active");
        require(buyTax <= MAX_TAX_LIMIT_BPS, "Buy tax exceeds limit");
        require(sellTax <= MAX_TAX_LIMIT_BPS, "Sell tax exceeds limit");
        require(transferTax <= MAX_TAX_LIMIT_BPS, "Transfer tax exceeds limit");

        taxSettings.buyTaxBps = buyTax;
        taxSettings.sellTaxBps = sellTax;
        taxSettings.transferTaxBps = transferTax;
        lastTaxChange = block.timestamp;

        emit TaxSettingsUpdated(buyTax, sellTax, transferTax);
    }}

    function setTaxDistribution(
        uint16 liquidityShare,
        uint16 marketingShare,
        uint16 developmentShare,
        uint16 reflectionShare,
        uint16 burnShare
    ) external onlyOwner {{
        require(taxModifiable, "Tax modifications disabled");
        uint16 total = liquidityShare + marketingShare + developmentShare + reflectionShare + burnShare;
        require(total == 10000, "Shares must total 100%");

        taxSettings.liquidityShareBps = liquidityShare;
        taxSettings.marketingShareBps = marketingShare;
        taxSettings.developmentShareBps = developmentShare;
        taxSettings.reflectionShareBps = reflectionShare;
        taxSettings.burnShareBps = burnShare;
    }}

    function setTaxEnabled(bool enabled) external onlyOwner {{
        taxSettings.enabled = enabled;
    }}

    function setFeeRecipients(
        address _liquidity,
        address _marketing,
        address _development
    ) external onlyOwner {{
        liquidityWallet = _liquidity;
        marketingWallet = _marketing;
        developmentWallet = _development;
        emit FeeRecipientUpdated("liquidity", _liquidity);
        emit FeeRecipientUpdated("marketing", _marketing);
        emit FeeRecipientUpdated("development", _development);
    }}
'''

    if anti_whale.enabled:
        contract += f'''
    // Anti-whale settings
    function setMaxWalletAmount(uint256 amount) external onlyOwner {{
        require(amount >= _TOTAL_SUPPLY / 100, "Max wallet too low");  // Min 1%
        maxWalletAmount = amount;
        emit LimitsUpdated(maxWalletAmount, maxTransactionAmount);
    }}

    function setMaxTransactionAmount(uint256 amount) external onlyOwner {{
        require(amount >= _TOTAL_SUPPLY / 200, "Max transaction too low");  // Min 0.5%
        maxTransactionAmount = amount;
        emit LimitsUpdated(maxWalletAmount, maxTransactionAmount);
    }}

    function setAntiWhaleEnabled(bool enabled) external onlyOwner {{
        antiWhaleEnabled = enabled;
    }}
'''

    if ContractFeature.MINTABLE in features and security.can_mint:
        contract += f'''
    // Minting
    function mint(address to, uint256 amount) external onlyOwner {{
        require(mintingEnabled, "Minting disabled");
        _mint(to, amount);
    }}

    function setMintingEnabled(bool enabled) external onlyOwner {{
        mintingEnabled = enabled;
    }}
'''

    if ContractFeature.BURNABLE in features and security.can_burn:
        contract += f'''
    // Burning
    function burn(uint256 amount) external {{
        _burn(msg.sender, amount);
    }}

    function burnFrom(address account, uint256 amount) external {{
        _spendAllowance(account, msg.sender, amount);
        _burn(account, amount);
    }}
'''

    contract += f'''
    // Pause functionality
    function pause() external onlyOwner {{
        _pause();
    }}

    function unpause() external onlyOwner {{
        _unpause();
    }}

    // Time-locked sensitive operations
    function queueRenounceOwnership() external onlyOwner {{
        pendingActions[keccak256("renounceOwnership")] = block.timestamp;
    }}

    function executeRenounceOwnership() external onlyOwner timeLocked(keccak256("renounceOwnership")) {{
        renounceOwnership();
    }}

    // ═══════════════════════════════════════════════════════════
    // VIEW FUNCTIONS
    // ═══════════════════════════════════════════════════════════
    function getTaxForTransfer(address from, address to) external view returns (uint256) {{
        if (!taxSettings.enabled) return 0;
        if (isWhitelisted[from] || isWhitelisted[to]) return 0;

        if (from == uniswapV2Pair) return taxSettings.buyTaxBps;
        if (to == uniswapV2Pair) return taxSettings.sellTaxBps;
        return taxSettings.transferTaxBps;
    }}

    function decimals() public pure override returns (uint8) {{
        return _DECIMALS;
    }}

    receive() external payable {{}}
}}
'''

    return contract

